<?php $orderLabels=['new'=>'Nouă','confirmed'=>'Confirmată','processing'=>'În pregătire','ready_for_shipping'=>'Pregătită pentru curier','shipped'=>'Expediată','delivered'=>'Livrată','cancelled'=>'Anulată','return_requested'=>'Retur solicitat','returned'=>'Returnată','partially_refunded'=>'Rambursată parțial','refunded'=>'Rambursată'];$paymentLabels=['unpaid'=>'Neplătită','pending'=>'În așteptare','paid'=>'Plătită','failed'=>'Eșuată','partially_refunded'=>'Rambursată parțial','refunded'=>'Rambursată']; ?>
<section class="admin-page-head"><div><p class="eyebrow">OPERAȚIUNI</p><h1>Comenzi</h1></div><a class="admin-button secondary" href="?export=csv">Export CSV</a></section><section class="admin-panel"><form class="admin-filters" method="get"><input type="search" name="q" value="<?= e($q) ?>" placeholder="Număr, client, email sau telefon"><select name="status"><option value="">Toate statusurile</option><?php foreach($orderLabels as $value=>$label): ?><option value="<?= e($value) ?>" <?= $status===$value?'selected':'' ?>><?= e($label) ?></option><?php endforeach; ?></select><button class="admin-button" type="submit">Filtrează</button></form><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Comandă</th><th>Client</th><th>Tip plată</th><th>Plată</th><th>Status</th><th>Data</th><th>Total</th></tr></thead><tbody><?php foreach($orders as $order): ?><tr><td><a href="<?= e(url('/admin/comenzi/'.$order['id'])) ?>"><strong><?= e($order['order_number']) ?></strong></a></td><td><?= e($order['email']) ?><small><?= e($order['phone']) ?></small></td><td><span class="status-pill <?= $order['payment_method']==='stripe'&&$order['payment_status']==='paid'?'success':'' ?>"><?= $order['payment_method']==='stripe'?($order['payment_status']==='paid'?'Card — plătită':'Card — în așteptare'):'Ramburs la curier' ?></span></td><td><span class="status-pill"><?= e($paymentLabels[$order['payment_status']]??$order['payment_status']) ?></span></td><td><span class="status-pill accent"><?= e($orderLabels[$order['order_status']]??$order['order_status']) ?></span></td><td><?= date('d.m.Y H:i',strtotime($order['created_at'])) ?></td><td><?= money($order['grand_total_minor']) ?></td></tr><?php endforeach; ?></tbody></table></div></section>